1	/*
2	Attention, as a fallback when we do not use the Flash Attention from cuDNN
3	*/
4	#include <assert.h>
5	// llmc internal imports
6	#include "cuda_common.h"
7	#include "cuda_utils.cuh"
8	#include "cublas_common.h"
9	
10	// ----------------------------------------------------------------------------
11	// CUDA kernels
12	
13	// inputs floatX, outputs FP32 (for current FP32-only activation path for this WIP)
14	__global__ void permute_kernel(floatX* q, floatX* k, floatX* v,
15	                               const floatX* inp,
16	                               int B, int N, int NH, int d) {
17	    // okay so now, this kernel wants Q,K,V to all be of shape (B, NH, N, d)
18	    // but instead, we have a single tensor QKV (inp) of shape (B, N, 3, NH, d)
19	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
20	    if (idx >= B * NH * N * d) { return; }
21	
22	    // Q[b][nh_][n][d_] = inp[b][n][0][nh_][d_]
23	    int b = idx / (NH * N * d);
24	    int rest = idx % (NH * N * d);
25	    int nh_ = rest / (N * d);
26	    rest = rest % (N * d);
27	    int n = rest / d;
28	    int d_ = rest % d;
29	    int inp_idx = (b * N * 3 * NH * d) + (n * 3 * NH * d) + (0 * NH * d) + (nh_ * d) + d_;
30	    q[idx] = __ldcs(&inp[inp_idx]);
31	    k[idx] = __ldcs(&inp[inp_idx + NH * d]);
32	    v[idx] = __ldcs(&inp[inp_idx + 2 * (NH * d)]);
33	}
34	
35	__global__ void permute_kernel_backward(floatX* dinp,
36	                                        const floatX* dq, const floatX* dk, const floatX* dv,
37	                                        int B, int N, int NH, int d) {
38	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
39	    if (idx >= B * NH * N * d) { return; }
40	
41	    int b = idx / (NH * N * d);
42	    int rest = idx % (NH * N * d);
43	    int nh_ = rest / (N * d);
44	    rest = rest % (N * d);
45	    int n = rest / d;
46	    int d_ = rest % d;
47	
48	    int inp_idx = (b * N * 3 * NH * d) + (n * 3 * NH * d) + (0 * NH * d) + (nh_ * d) + d_;
49	    dinp[inp_idx] = dq[idx];
50	    dinp[inp_idx + NH * d] = dk[idx];
51	    dinp[inp_idx + 2 * (NH * d)] = dv[idx];
52	}
53	
54	__global__ void unpermute_kernel(floatX* inp, floatX *out, int B, int N, int NH, int d) {
55	   // out has shape (B, nh, N, d) but we need to unpermute it to (B, N, nh, d)
56	
57	    int idx = (blockIdx.x * blockDim.x + threadIdx.x);
58	    // out[b][n][nh_][d_] <- inp[b][nh_][n][d_]
59	    if (idx >= B * NH * N * d) { return; }
60	
61	    int b = idx / (NH * N * d);
62	    int rest = idx % (NH * N * d);
63	    int nh_ = rest / (N * d);
64	    rest = rest % (N * d);
65	    int n = rest / d;
66	    int d_ = rest % d;
67	    int other_idx = (b * NH * N * d) + (n * NH * d) + (nh_ * d) + d_;
68	    out[other_idx] = __ldcs(&inp[idx]);
69	}
70	
71	__global__ void unpermute_kernel_backward(floatX* dinp, const floatX *dout, int B, int N, int NH, int d) {
72	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
73	    if (idx >= B * NH * N * d) { return; }
74	
75	    int b = idx / (NH * N * d);
76	    int rest = idx % (NH * N * d);
77	    int nh_ = rest / (N * d);
78	    rest = rest % (N * d);
79	    int n = rest / d;
80	    int d_ = rest % d;
81	    int other_idx = (b * NH * N * d) + (n * NH * d) + (nh_ * d) + d_;
82	    dinp[idx] = (floatX)dout[other_idx];
83	}
84	
85	__global__ void softmax_forward_kernel5(floatX* out, float inv_temperature, const floatX* inp, int N, int T) {
86	    // inp, out shape: (N, T, T), where N = B * NH
87	    // fuses the multiplication by scale inside attention
88	    // directly autoregressive, so we only compute the lower triangular part
89	    // uses the online softmax algorithm
90	    assert(T % 4  == 0);
91	    int lane_id = threadIdx.x % WARP_SIZE;
92	    int warp_id = threadIdx.x / WARP_SIZE;
93	    int num_warps = blockDim.x / WARP_SIZE;
94	
95	    // micro-optimization: we iterate backwards so that
96	    // after the softmax backward operation completes, the cache retains the
97	    // part of the matrix close to the upper left corner, which benefits the
98	    // matmul operation that immediately follows.
99	    // int idx = blockIdx.x * warp.meta_group_size() + warp.meta_group_rank(); // forward order
100	    int idx = (gridDim.x - blockIdx.x - 1) * num_warps + warp_id; // backward order
101	    if(idx >= N * T) {
102	        return;
103	    }
104	    int own_pos = idx % T;
105	    int pos_by_4 = own_pos / 4;
106	
107	    // one row of inp, i.e. inp[idx, :] of shape (T,)
108	    const floatX* x = inp + idx * T;
109	
110	    // not INF, so we don't get NaNs accidentally when subtracting two values.
111	    const float flt_max = 340282346638528859811704183484516925440.0f; // to avoid including float.h
112	    float maxval = -flt_max;
113	    float sumval = 0.0f;
114	
115	    const floatX* x_aligned = reinterpret_cast<const floatX*>(__builtin_assume_aligned(x, 16));
116	    for (int i = lane_id; i < pos_by_4; i += WARP_SIZE) {
117	        float regarray[4];
118	        for (int k = 0; k < 4; ++k) {
119	            regarray[k] = (float)x_aligned[4*i + k];
120	        }
121	        float old_maxval = maxval;
122	        for(int k = 0; k < 4; ++k) {
123	            maxval = fmaxf(maxval, regarray[k]);
124	        }
125	        sumval *= expf(inv_temperature * (old_maxval - maxval));
126	        for(int k = 0; k < 4; ++k) {
127	            sumval += expf(inv_temperature * (regarray[k] - maxval));
128	        }
129	    }
130	
131	    if(4*pos_by_4 + lane_id <= own_pos) {
132	        float old_maxval = maxval;
133	        maxval = fmaxf(maxval, (float)x[4*pos_by_4 + lane_id]);
134	        sumval *= expf(inv_temperature * (old_maxval - maxval));
135	        sumval += expf(inv_temperature * ((float)x[4*pos_by_4 + lane_id] - maxval));
136	    }
137	
138	    float global_maxval = warpReduceMax(maxval);
139	    sumval *= expf(inv_temperature * (maxval - global_maxval));
140	
141	    float sum = warpReduceSum(sumval);
142	    float norm = 1.f / sum;
143	
144	    // divide the whole row by the sum
145	    for (int i = lane_id; i <= own_pos; i += WARP_SIZE) {
146	        // recalculation is faster than doing the round-trip through memory.
147	        float ev = expf(inv_temperature * ((float)__ldcs(x + i) - global_maxval));
148	        __stcs(out + idx * T + i, (floatX)(ev * norm));
149	    }
150	}
151	
152	__global__ void softmax_autoregressive_backward_inplace_kernel(floatX* datt, const floatX* att,
153	                                                               int B, int T, int C, float scale) {
154	    constexpr const int BlockSize = 256;
155	    constexpr int T_per_block = 4;
156	
157	    // go through blocks in reverse order, so the slowest block starts first
158	    int t0 = T - 1 - T_per_block*blockIdx.x;
159	    int idx = blockIdx.y;
160	
161	    att += idx * T * T;
162	    datt += idx * T * T;
163	
164	    for(int to = 0; to < T_per_block; ++to) {
165	        int t = t0 - to;
166	        if(t < 0) return;
167	        const floatX* att_bth = att + t * T;
168	        const floatX* datt_bth = datt + t * T;
169	        floatX* dpreatt_bth = datt + t * T;
170	
171	        float local_sum = 0;
172	        for (int t2 = threadIdx.x; t2 <= t; t2 += BlockSize) {
173	            local_sum += (float)att_bth[t2] * (float)datt_bth[t2];
174	        }
175	
176	        local_sum = blockReduce<warpReduceSum>(local_sum);
177	
178	        for (int t3 = threadIdx.x; t3 < T; t3 += BlockSize) {
179	            // don't touch the cache. Some parts will still be here from the previous loop, and
180	            // we want to exploit those.
181	            if(t3 <= t) {
182	                float acc = (float) __ldcs(att_bth + t3) * ((float) __ldcs(datt_bth + t3) - local_sum);
183	                __stcs(dpreatt_bth + t3, (floatX) (scale * acc));
184	            } else {
185	                // explicitly set non-causal elements to zero
186	                __stcs(dpreatt_bth + t3, (floatX)0.f);
187	            }
188	        }
189	    }
190	}
191	
192	// ----------------------------------------------------------------------------
193	// kernel launchers
194	
195	void attention_forward(floatX* out, floatX* qkvr, floatX* att,
196	                       floatX* inp,
197	                       int B, int T, int C, int NH, cudaStream_t stream) {
198	    NVTX_RANGE_FN();
199	    // Note: `inp` is not needed for backward pass, so we re-use it as a scratch buffer.
200	    // Its contents will be overwritten by this function.
201	    const int block_size = 256;
202	
203	    // inp is (B, T, 3C) QKV
204	    // preatt, att are (B, NH, T, T)
205	    // output is (B, T, C)
206	    const int HS = C / NH; // head size
207	
208	    // permute and separate inp from (B, T, 3, NH, HS) to 3X (B, NH, T, HS)
209	    floatX *q, *k, *v;
210	    q = qkvr + 0 * B * T * C;
211	    k = qkvr + 1 * B * T * C;
212	    v = qkvr + 2 * B * T * C;
213	    int total_threads = B * NH * T * HS;
214	    int num_blocks = CEIL_DIV(total_threads, block_size);
215	    permute_kernel<<<num_blocks, block_size, 0, stream>>>(q, k, v, inp, B, T, NH, HS);
216	
217	    floatX* preatt = inp; // reuse inp as scratch buffer
218	    matmul_cublaslt(preatt, k, q, nullptr, T, T, HS, stream, true, false, B * NH, T * HS, T * HS, T * T);
219	
220	    // multiply all elements of preatt elementwise by scale
221	    float scale = 1.f / sqrtf(HS);
222	    int grid_size = CEIL_DIV(B * NH * T * WARP_SIZE, block_size);
223	    softmax_forward_kernel5<<<grid_size, block_size, 0, stream>>>(att, scale, preatt, B * NH, T);
224	
225	    // new approach: first cuBLAS another batched matmul
226	    floatX* vaccum = inp;
227	    // y = att @ v # (B, nh, T, T) @ (B, nh, T, hs) -> (B, nh, T, hs)
228	    matmul_cublaslt(vaccum, v, att, nullptr, HS, T, T, stream, false, false, B * NH, T * HS, T * T, T * HS);
229	
230	    // now unpermute
231	    // y = y.transpose(1, 2).contiguous().view(B, T, C) # re-assemble all head outputs side by side
232	    num_blocks = CEIL_DIV(B * T * C, block_size);
233	    unpermute_kernel<<<num_blocks, block_size, 0, stream>>>(vaccum, out, B, T, NH, HS);
234	    cudaCheck(cudaGetLastError());
235	}
236	
237	// the sequence of transformations in this compound op is:
238	// inp (B,T,3C) -> qkvr (B,T,3C) -> preatt (B,NH,T,T) -> att (B,NH,T,T) -> vaccum (B,T,C) -> out (B,T,C)
239	void attention_backward(floatX* dinp, floatX* dqkvr, floatX* datt, floatX* scratch,
240	                        const floatX* dout,
241	                        const floatX* qkvr, const floatX* att,
242	                        int B, int T, int C, int NH, cudaStream_t stream) {
243	    NVTX_RANGE_FN();
244	    const int block_size = 256;
245	    const int HS = C / NH; // head size
246	
247	    // unpack convenience pointers into q, k, v
248	    const floatX *q, *k, *v;
249	    q = qkvr + 0 * B * T * C;
250	    k = qkvr + 1 * B * T * C;
251	    v = qkvr + 2 * B * T * C;
252	    floatX *dq, *dk, *dv;
253	    dq = dqkvr + 0 * B * T * C;
254	    dk = dqkvr + 1 * B * T * C;
255	    dv = dqkvr + 2 * B * T * C;
256	
257	    // backward through the unpermute operation
258	    int num_blocks = CEIL_DIV(B * T * C, block_size);
259	    unpermute_kernel_backward<<<num_blocks, block_size, 0, stream>>>(scratch, dout, B, T, NH, HS);
260	    // backward into datt
261	    matmul_cublaslt(datt, v, scratch, nullptr, T, T, HS, stream, true, false, B * NH, T * HS, T * HS, T * T);
262	    // backward into dv
263	    matmul_cublaslt(dv, scratch, att, nullptr, HS, T, T, stream, false, true, B * NH, T * HS, T * T, T * HS);
264	    const float scale = 1.0f / sqrtf((float)HS);
265	    // backward into preatt. this is an in-place operation; datt turns into dpreatt here
266	    softmax_autoregressive_backward_inplace_kernel<<<dim3(T / 4, B * NH), 256>>>(datt, att, B, T, C, scale);
267	    const floatX* dpreatt = datt;
268	    // backward into q
269	    matmul_cublaslt(dq, k, dpreatt, nullptr, HS, T, T, stream, false, false, B * NH, T * HS, T * T, T * HS);
270	    // backward into k
271	    matmul_cublaslt(dk, q, dpreatt, nullptr, HS, T, T, stream, false, true, B * NH, T * HS, T * T, T * HS);
272	    // backward into inp
273	    num_blocks = CEIL_DIV(B * NH * T * HS, block_size);
274	    permute_kernel_backward<<<num_blocks, block_size, 0, stream>>>(dinp, dq, dk, dv, B, T, NH, HS);
275	    cudaCheck(cudaGetLastError());
276	}
