181	                            .set_dim({1, 1, 1, 1})
182	                            .set_stride({1, 1, 1, 1})
183	                            .set_is_pass_by_value(true)
184	                            .set_uid(Attn_scale_UID)
185	                            .set_data_type(fe::DataType_t::FLOAT));
