209	    // By default, cuDNN uses up to 256MiB of workspace, so we don't want to just allocate the maximum
210	    if (graph->get_workspace_size() > cudnn_workspace_size) {
211	        if (cudnn_workspace_size > 0) {
212	            cudaCheck(cudaFree(cudnn_workspace));
213	        }
214	        cudnn_workspace_size = graph->get_workspace_size();
215	        cudaCheck(cudaMalloc(&cudnn_workspace, cudnn_workspace_size));
216	    }
217	
218	    user_maintained_cache_bwd.insert({key, graph});
219	    return graph;
220	}
