222	void attention_forward_cudnn(floatX* out,  // output: (B, T, NH, HS)
223	                             float* stats, // output for backward pass: (B, NH, T)
224	                             floatX* inp,  // input: (B, T, 3, NH, HS) QKV
225	                             int B, int T, int NH, int C, cudaStream_t stream) {
226	    NVTX_RANGE_FN();
227	    int HS = C / NH; // number of features per head
228	    bool is_inference_only = (stats == nullptr);
229	
230	    cuDNNCheck(cudnnSetStream(cudnn_handle, stream));
231	
232	    // Get graph and tensors from cache (or generate it on first use)
233	    auto graph = lookup_cache_or_build_graph_fwd(B, NH, T, HS, is_inference_only);
234	
235	    // Prepare all the tensor pointers for executing the graph
236	    void* devPtrQ = inp;
237	    void* devPtrK = (inp + C);
238	    void* devPtrV = (inp + 2 * C);
239	    float attn_scale_cpu = 1.0 / sqrtf(HS);
240	    void* devPtrO = out;
241	
242	    // Build variant pack
243	    std::unordered_map<int64_t , void*> variant_pack = {
244	        {Q_UID, devPtrQ}, {K_UID, devPtrK}, {V_UID, devPtrV}, {Attn_scale_UID, &attn_scale_cpu}, {O_UID, devPtrO}};
245	
246	    // Add the stats tensor unless we are only doing inference (only needed for backward pass)
247	    if (is_inference_only == false) {
248	        variant_pack[Stats_UID] = stats;
249	    }
250	
251	    // Execute graph
252	    checkCudnnFE(graph->execute(cudnn_handle, variant_pack, cudnn_workspace));
253	    cudaCheck(cudaGetLastError());
254	}
255	
256	void attention_backward_cudnn(floatX* dqkvr,                                       // output
257	                              floatX* dout, floatX* qkvr, floatX* o, float* stats, // inputs
258	                              int B, int T, int NH, int C, cudaStream_t stream) {
259	    NVTX_RANGE_FN();
260	    int HS = C / NH; // number of features per head
261	
262	    // Get graph and tensors from cache (or generate it on first use)
263	    auto graph = lookup_cache_or_build_graph_bwd(B, NH, T, HS);
264	
265	    // Prepare all the tensor pointers for executing the graph
266	    void* devPtrQ = qkvr;
267	    void* devPtrK = (qkvr + NH * HS);
268	    void* devPtrV = (qkvr + 2 * NH * HS);
269	    void* devPtrO = o;
270	    void* devPtrdO = dout;
271	    void* devPtrStats = stats;
272	    float attn_scale_cpu = 1.0 / sqrtf(HS);
273	
274	    void* devPtrdQ = dqkvr;
275	    void* devPtrdK = (dqkvr + NH * HS);
276	    void* devPtrdV = (dqkvr + 2 * NH * HS);
277	
278	    // Build variant pack that links each tensor to its data pointer
279	    std::unordered_map<int64_t, void*> variant_pack = {
280	        {Q_UID, devPtrQ}, {K_UID, devPtrK}, {V_UID, devPtrV}, {O_UID, devPtrO}, {dO_UID, devPtrdO}, {Stats_UID, devPtrStats},
281	        {dQ_UID, devPtrdQ}, {dK_UID, devPtrdK}, {dV_UID, devPtrdV},
282	        {Attn_scale_UID, &attn_scale_cpu}};
283	
284	    // Execute graph
285	    cuDNNCheck(cudnnSetStream(cudnn_handle, stream));
286	    checkCudnnFE(graph->execute(cudnn_handle, variant_pack, cudnn_workspace));
287	    cudaCheck(cudaGetLastError());
288	}
289	
290	void create_cudnn() {
291	    cuDNNCheck(cudnnCreate(&cudnn_handle));
292	}
293	
294	void destroy_cudnn() {
295	    if (cudnn_workspace != NULL) { cudaCheck(cudaFree(cudnn_workspace)); }
296	    cuDNNCheck(cudnnDestroy(cudnn_handle));
297	}

